  1→package lexer
  2→
  3→import (
  4→	"iter"
  5→	"unicode"
  6→	"unicode/utf8"
  7→
  8→	"github.com/135yshr/meow/pkg/token"
  9→)
 10→
 11→// Lexer tokenizes Meow source code.
 12→type Lexer struct {
 13→	input string
 14→	file  string
 15→	pos   int
 16→	line  int
 17→	col   int
 18→}
 19→
 20→// New creates a new Lexer for the given source.
 21→func New(input, file string) *Lexer {
 22→	return &Lexer{
 23→		input: input,
 24→		file:  file,
 25→		pos:   0,
 26→		line:  1,
 27→		col:   1,
 28→	}
 29→}
 30→
 31→func (l *Lexer) peek() rune {
 32→	if l.pos >= len(l.input) {
 33→		return 0
 34→	}
 35→	r, _ := utf8.DecodeRuneInString(l.input[l.pos:])
 36→	return r
 37→}
 38→
 39→func (l *Lexer) advance() rune {
 40→	if l.pos >= len(l.input) {
 41→		return 0
 42→	}
 43→	r, size := utf8.DecodeRuneInString(l.input[l.pos:])
 44→	l.pos += size
 45→	if r == '\n' {
 46→		l.line++
 47→		l.col = 1
 48→	} else {
 49→		l.col++
 50→	}
 51→	return r
 52→}
 53→
 54→func (l *Lexer) peekAt(offset int) rune {
 55→	p := l.pos + offset
 56→	if p >= len(l.input) {
 57→		return 0
 58→	}
 59→	r, _ := utf8.DecodeRuneInString(l.input[p:])
 60→	return r
 61→}
 62→
 63→func (l *Lexer) makeToken(typ token.TokenType, lit string, pos token.Position) token.Token {
 64→	return token.Token{Type: typ, Literal: lit, Pos: pos}
 65→}
 66→
 67→func (l *Lexer) currentPos() token.Position {
 68→	return token.Position{File: l.file, Line: l.line, Column: l.col}
 69→}
 70→
 71→func (l *Lexer) skipWhitespace() {
 72→	for l.pos < len(l.input) {
 73→		r := l.peek()
 74→		if r == ' ' || r == '\t' || r == '\r' {
 75→			l.advance()
 76→		} else {
 77→			break
 78→		}
 79→	}
 80→}
 81→
 82→func (l *Lexer) readString() token.Token {
 83→	pos := l.currentPos()
 84→	l.advance() // skip opening quote
 85→	start := l.pos
 86→	for l.pos < len(l.input) {
 87→		r := l.peek()
 88→		if r == '"' {
 89→			lit := l.input[start:l.pos]
 90→			l.advance() // skip closing quote
 91→			return l.makeToken(token.STRING, lit, pos)
 92→		}
 93→		if r == '\\' {
 94→			l.advance() // skip backslash
 95→		}
 96→		l.advance()
 97→	}
 98→	return l.makeToken(token.ILLEGAL, l.input[start:l.pos], pos)
 99→}
100→
101→func (l *Lexer) readNumber() token.Token {
102→	pos := l.currentPos()
103→	start := l.pos
104→	isFloat := false
105→	for l.pos < len(l.input) {
106→		r := l.peek()
107→		if r == '.' && l.peekAt(1) != '.' {
108→			if isFloat {
109→				break
110→			}
111→			isFloat = true
112→			l.advance()
113→			continue
114→		}
115→		if !unicode.IsDigit(r) {
116→			break
117→		}
118→		l.advance()
119→	}
120→	lit := l.input[start:l.pos]
121→	if isFloat {
122→		return l.makeToken(token.FLOAT, lit, pos)
123→	}
124→	return l.makeToken(token.INT, lit, pos)
125→}
126→
127→func (l *Lexer) readIdent() token.Token {
128→	pos := l.currentPos()
129→	start := l.pos
130→	for l.pos < len(l.input) {
131→		r := l.peek()
132→		if !unicode.IsLetter(r) && !unicode.IsDigit(r) && r != '_' {
133→			break
134→		}
135→		l.advance()
