150→func (l *Lexer) readBlockComment() token.Token {
151→	pos := l.currentPos()
152→	l.advance() // skip ~
153→	start := l.pos
154→	for l.pos < len(l.input) {
155→		if l.peek() == '~' && l.peekAt(1) == '-' {
156→			lit := l.input[start:l.pos]
157→			l.advance() // ~
158→			l.advance() // -
159→			tok := l.makeToken(token.COMMENT, lit, pos)
160→			tok.BlockComment = true
161→			return tok
162→		}
163→		l.advance()
164→	}
165→	return l.makeToken(token.ILLEGAL, l.input[start:l.pos], pos)
166→}
