346→						return
347→					}
348→				} else {
349→					if !yield(l.makeToken(token.ILLEGAL, "|", pos)) {
350→						return
351→					}
352→				}
353→			case r == '.':
354→				l.advance()
355→				if l.peek() == '.' {
356→					l.advance()
357→					if !yield(l.makeToken(token.DOTDOT, "..", pos)) {
358→						return
359→					}
360→				} else {
361→					if !yield(l.makeToken(token.DOT, ".", pos)) {
362→						return
363→					}
364→				}
365→			case r == '~':
366→				l.advance()
