166→func (interp *Interpreter) execRange(s *ast.RangeStmt, env *Environment) {
167→	var start, end int64
168→	if s.Start != nil {
169→		start = meowrt.AsInt(interp.evalExpr(s.Start, env))
170→	}
171→	end = meowrt.AsInt(interp.evalExpr(s.End, env))
172→
173→	if s.Start == nil {
174→		// count form: purr i (n) → i = 0..n-1
175→		for i := int64(0); i < end; i++ {
176→			interp.checkStep()
177→			child := env.Child()
178→			child.Define(s.Var, meowrt.NewInt(i))
179→			interp.execBlock(s.Body, child)
180→		}
181→	} else if s.Inclusive {
182→		// range form inclusive: purr i (a..b) → i = a..b
183→		for i := start; i <= end; i++ {
184→			interp.checkStep()
185→			child := env.Child()
186→			child.Define(s.Var, meowrt.NewInt(i))
187→			interp.execBlock(s.Body, child)
188→		}
189→	} else {
190→		// range form exclusive
191→		for i := start; i < end; i++ {
192→			interp.checkStep()
193→			child := env.Child()
194→			child.Define(s.Var, meowrt.NewInt(i))
195→			interp.execBlock(s.Body, child)
196→		}
197→	}
198→}
