212→	if len(args) < len(fn.Params) {
213→		// Partial application: capture supplied args and return a new function
214→		captured := make([]meowrt.Value, len(args))
215→		copy(captured, args)
216→		remaining := len(fn.Params) - len(args)
217→		return meowrt.NewFuncWithArity(fn.Name, remaining, func(moreArgs ...meowrt.Value) meowrt.Value {
218→			allArgs := make([]meowrt.Value, 0, len(captured)+len(moreArgs))
219→			allArgs = append(allArgs, captured...)
220→			allArgs = append(allArgs, moreArgs...)
221→			return interp.callUserFunc(fn, allArgs, closure)
