func (interp *Interpreter) execRange(s *ast.RangeStmt, env *Environment) {
    var start, end int64
    if s.Start != nil {
        start = meowrt.AsInt(interp.evalExpr(s.Start, env))
    }
    end = meowrt.AsInt(interp.evalExpr(s.End, env))

    if s.Start == nil {
        // count form: purr i (n) → i = 0..n-1
        for i := int64(0); i < end; i++ {
            interp.checkStep()
            child := env.Child()
            child.Define(s.Var, meowrt.NewInt(i))
            interp.execBlock(s.Body, child)
        }
    } else if s.Inclusive {
        // range form inclusive: purr i (a..b) → i = a..b
        for i := start; i <= end; i++ {
            interp.checkStep()
            child := env.Child()
            child.Define(s.Var, meowrt.NewInt(i))
            interp.execBlock(s.Body, child)
        }
    } else {
        // range form exclusive
        for i := start; i < end; i++ {
            interp.checkStep()
            child := env.Child()
            child.Define(s.Var, meowrt.NewInt(i))
            interp.execBlock(s.Body, child)
        }
    }
}
```

**Execution Flow:**
1. Evaluate Start (if present) and End expressions to `int64`
2. Create child environment for each iteration
3. Define loop variable in child environment as `meow.Value` integer
4. Execute block in child environment
5. Three forms:
