	got := runMeow(t, `
nyan xs = [1, 2, 3, 4, 5]
nyan result = xs |=| picky(paw(x int) { x > 2 }) |=| lick(paw(x int) { x * 10 })
nya(result)
`)
	if strings.TrimSpace(got) != "[30, 40, 50]" {
		t.Errorf("got %q", got)
	}
